import json

def extract_json(text, model, tokenizer):
    prompt = f"""Extract structured data. Return ONLY valid JSON.

Text: "{text}"

JSON: {{"person": """

    messages = [{"role": "user", "content": prompt}]
    formatted = tokenizer.apply_chat_template(
        messages, tokenize=False, add_generation_prompt=True
    )
    inputs = tokenizer(formatted, return_tensors="pt").to(model.device)
    output = model.generate(
        **inputs, max_new_tokens=80, temperature=0.1
    )
    raw = tokenizer.decode(
        output[0][inputs["input_ids"].shape[-1]:],
        skip_special_tokens=True
    )
    # Reconstruct the full JSON (we started it in the prompt)
    full_json = '{"person": "' + raw.split('}')[0] + '}'
    try:
        return json.loads(full_json)
    except json.JSONDecodeError:
        return {"raw": raw, "error": "parse_failed"}

result = extract_json(
    "Meeting with Sarah on Friday at 3pm about budget",
    model, tokenizer
)
print(type(result).__name__)
print("person" in result)
